let basePath = '';
/** Sets the library's base path to the specified directory. */
export function setBasePath(path) {
    basePath = path;
}
/** Gets the library's base path. The base path is used to load assets such as icons and images. */
export function getBasePath(subpath = '') {
    // Return the base path without a trailing slash. Append the subpath if provided.
    return (basePath.replace(/\/$/, '') +
        (subpath ? `/${subpath.replace(/^\//, '')}` : ``));
}
